function autoFormatTime(w){let s=w['value']['replace'](/\D/g,'');switch(s['length']>0x4&&(s=s['slice'](0x0,0x4)),s['length']){case 0x0:case 0x1:case 0x2:w['value']=s;break;case 0x3:if(parseInt(s['slice'](0x0,0x2),0xa)<=0x17)w['value']=s['slice'](0x0,0x2)+':'+s['slice'](0x2);else{let z=s['slice'](0x0,0x1)['padStart'](0x2,'0'),X=s['slice'](0x1);w['value']=z+':'+X;}break;case 0x4:let L=s['slice'](0x0,0x2),Y=s['slice'](0x2);w['value']=L+':'+Y;}}function transformTimeValue(w){let s=w['trim']();if(/^\d{2}$/['test'](s))return s[0x0]['padStart'](0x2,'0')+':'+s[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](s))return 0x3===s['length']?parseInt(s['slice'](0x0,0x2),0xa)<=0x17?s['slice'](0x0,0x2)+':'+s['slice'](0x2):s['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+s['slice'](0x1):s['slice'](0x0,0x2)+':'+s['slice'](0x2);if(s['includes'](':')){let [L,Y]=s['split'](':');return Y||(Y='00'),L=L['padStart'](0x2,'0'),Y=Y['padStart'](0x2,'0'),L+':'+Y;}return s;}